;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 6]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@notice text="Orc gathering spot nearby."

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@roadguide n="Northrop Village" s="Sapphire City" w="Yanek Hot Spring"

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@notice text="Welcome to Yanek Hot Springs!<r>Please present your ticket at the entrance."

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] WAY == "s" || WAY == "n"

[if exp='game.protectHeroines']
	@notice text="Temporarily closed"
	@walk move=n
	[eventoff]
[endif]

[if exp='WAY == "n"']
	; ロッカーの中に預けたままのアイテムは一時保管所へ移送される
	[iscript]
	tf.result = false;
	for(var i = 0; i < game.lockerRoom.trunk.count; i++)
	{
		var item = game.lockerRoom.trunk[i];
		if(item !== void)
		{
			tf.result = true;
			game.storeItemSomewhere(item, game.temporaryBox);
		}
	}
	game.lockerRoom.trunk = [];
	[endscript]
	@notice text="<y>Items left in the locker were transferred to the temporary storage area of the Item Warehouse." cond='tf.result'
	[eventoff]
[endif]

@question title="This is Yanek Hot Springs. Would you like to enter?<r><y> (Requires one hot spring ticket)"
[if exp='tf.result && game.party.ejectItem(o.温泉チケット)']
	@warp map=温泉・脱衣所 x=3 y=5 way=s sound=door1 cond='tf.result'
	[eventoff]
[endif]

[if exp='tf.result']
	@notice text="<y>You cannot enter the hot springs without a ticket."
[endif]
@walk move=n

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] o.スライム軍団の討伐.flag != 1 && o.スライム軍団.interruption == 0 && random < 0.2

; スライム軍団との決闘
@jump storage="duel.ks" target=*slimes_encounter

[eventoff]
;-------------------------------------------------------------------------------
*event_6
;[exp] true

@wait time=500
@walk turn=s cond='WAY != "s"'
@wait time=500 cond='WAY != "s"'
@fg l=orc_red left=250 top=45 b
@fg c=orc_red left=450 top=45 b
@fgf r=orc_red left=650 top=45
[texton]
[name n=Orc]「What the hell are you guys doing?」[k]
[name n=Orc]「This is our orc territory! Guys! Get 'em!」[k]
[textoff]
@clf

@monster pos=2 name=オークソルジャー
@monster pos=3 name=オークソルジャー
@monster pos=4 name=オークソルジャー
@callbattle gameover=true
@treasure item=ボム,ボム,たいまつ
@delevent

@wait time=300
[texton]
The orcs we just killed were probably guards. Their den must be nearby.
 [k]
[textoff]

[eventoff]
;-------------------------------------------------------------------------------
